async function generatePptx(d) {
  if (!d) return;
  const r = d.ringkasan;
  const btn = document.getElementById('pptxBtn');
  btn.textContent = 'Membuat PPTX...';
  btn.disabled = true;

  try {
    const pres = new PptxGenJS();
    pres.layout = 'LAYOUT_WIDE';
    pres.author = 'PT. UNIFAM';
    pres.title = `Evaluasi Kinerja Ekspedisi - ${d.ekspedisi}`;

    const NAVY = COLORS.navy, DEEP = COLORS.deep, TEAL = COLORS.teal, MINT = COLORS.mint;
    const GREEN = COLORS.green, LIGHT = COLORS.light, WHITE = COLORS.white, GREY = COLORS.grey, RED = COLORS.red;
    const W = 13.33, H = 7.5;
    const scoreColor = (v, t) => (v >= t ? GREEN : RED);

    function footer(slide, pageNum) {
      slide.addText(`Evaluasi Kinerja Ekspedisi  |  ${d.ekspedisi}  |  ${periodeLabel(d.periode)}`, {
        x: 0.5, y: H - 0.45, w: 8, h: 0.3, fontSize: 9, color: GREY, fontFace: 'Calibri', margin: 0
      });
      slide.addText(String(pageNum), { x: W - 1.0, y: H - 0.45, w: 0.5, h: 0.3, fontSize: 9, color: GREY, align: 'right', fontFace: 'Calibri', margin: 0 });
    }
    function sectionHeader(slide, kicker, title) {
      slide.addImage({ data: LOGO_SMALL_B64, x: W - 2.15, y: 0.32, w: 1.55, h: 0.77, sizing: { type: 'contain', w: 1.55, h: 0.77 } });
      slide.addText(kicker.toUpperCase(), { x: 0.6, y: 0.35, w: 9, h: 0.3, fontSize: 12, color: TEAL, bold: true, charSpacing: 2, fontFace: 'Calibri', margin: 0 });
      slide.addText(title, { x: 0.6, y: 0.62, w: 10, h: 0.6, fontSize: 28, color: NAVY, bold: true, fontFace: 'Cambria', margin: 0 });
    }

    // SLIDE 1: TITLE
    let s1 = pres.addSlide();
    s1.addImage({ data: BG_PHOTO_B64, x: 0, y: 0, w: W, h: H, sizing: { type: 'cover', w: W, h: H } });
    s1.addShape(pres.shapes.RECTANGLE, { x: 0, y: 0, w: W, h: H, fill: { color: '0B1220', transparency: 38 }, line: { type: 'none' } });
    s1.addText('F.00.00.00.00 Rev. 00', { x: 0.7, y: 0.4, w: 5, h: 0.3, fontSize: 10, color: 'D7DEE6', fontFace: 'Calibri', margin: 0 });
    s1.addText('LAPORAN EVALUASI KINERJA EKSPEDISI', { x: 0.7, y: 2.3, w: 11.5, h: 0.5, fontSize: 16, color: MINT, bold: true, charSpacing: 3, fontFace: 'Calibri', margin: 0 });
    // Nama ekspedisi bisa sangat panjang (mis. "Sentosa Prima Abadi (SPA)")
    // — kecilkan font & lebarkan area vertikal supaya tidak menabrak baris
    // "Periode" di bawahnya kalau perlu wrap ke 2 baris.
    const nameLen = String(d.ekspedisi).length;
    const nameFontSize = nameLen > 30 ? 30 : nameLen > 22 ? 38 : nameLen > 14 ? 46 : 54;
    s1.addText(d.ekspedisi, { x: 0.7, y: 2.8, w: 11.5, h: 1.6, fontSize: nameFontSize, color: WHITE, bold: true, fontFace: 'Cambria', margin: 0, valign: 'top' });
    s1.addText(`Periode  •  ${periodeLabel(d.periode)}`, { x: 0.7, y: 4.75, w: 11.5, h: 0.5, fontSize: 18, color: 'E8EDF2', fontFace: 'Calibri', margin: 0 });
    s1.addShape(pres.shapes.OVAL, { x: 10.6, y: 5.15, w: 1.6, h: 1.6, fill: { color: gradeColor(r.grade) }, line: { color: WHITE, width: 2 } });
    s1.addText(r.grade || '-', { x: 10.6, y: 5.15, w: 1.6, h: 1.6, fontSize: 44, bold: true, color: NAVY, align: 'center', valign: 'middle', fontFace: 'Cambria', margin: 0 });
    s1.addText('GRADE', { x: 10.6, y: 6.85, w: 1.6, h: 0.3, fontSize: 11, color: 'E8EDF2', align: 'center', bold: true, charSpacing: 2, fontFace: 'Calibri', margin: 0 });
    s1.addText('PT. UNIFAM  —  Divisi Logistik & Transportasi', { x: 0.7, y: 6.85, w: 8, h: 0.3, fontSize: 11, color: 'D7DEE6', fontFace: 'Calibri', margin: 0 });

    // SLIDE 2: RINGKASAN
    let s2 = pres.addSlide();
    s2.background = { color: WHITE };
    sectionHeader(s2, 'Ringkasan', 'Skor Kinerja Keseluruhan');
    s2.addShape(pres.shapes.ROUNDED_RECTANGLE, { x: 0.6, y: 1.55, w: 3.7, h: 4.6, rectRadius: 0.08, fill: { color: NAVY },
      shadow: { type: 'outer', color: '000000', blur: 8, offset: 3, angle: 45, opacity: 0.18 } });
    s2.addText('TOTAL SKOR', { x: 0.9, y: 1.9, w: 3.1, h: 0.35, fontSize: 13, color: '9FB3C8', bold: true, charSpacing: 2, fontFace: 'Calibri', margin: 0 });
    s2.addText((r.totalSkor != null ? r.totalSkor.toFixed(2) : '-') + '%', { x: 0.9, y: 2.25, w: 3.1, h: 1.1, fontSize: 50, color: WHITE, bold: true, fontFace: 'Cambria', margin: 0 });
    s2.addShape(pres.shapes.OVAL, { x: 0.9, y: 3.55, w: 1.1, h: 1.1, fill: { color: MINT } });
    s2.addText(r.grade || '-', { x: 0.9, y: 3.55, w: 1.1, h: 1.1, fontSize: 32, bold: true, color: NAVY, align: 'center', valign: 'middle', fontFace: 'Cambria', margin: 0 });
    s2.addText('Hasil evaluasi periode berjalan', { x: 0.9, y: 4.85, w: 3.1, h: 0.9, fontSize: 12, color: 'CADCFC', fontFace: 'Calibri', margin: 0 });

    const compRows = [
      [{ text: 'Komponen', options: { bold: true, color: WHITE, fill: { color: DEEP } } },
       { text: 'Bobot', options: { bold: true, color: WHITE, fill: { color: DEEP }, align: 'center' } },
       { text: 'Target', options: { bold: true, color: WHITE, fill: { color: DEEP }, align: 'center' } },
       { text: 'Skor', options: { bold: true, color: WHITE, fill: { color: DEEP }, align: 'center' } }],
      ['Mutu', { text: '10%', options: { align: 'center' } }, { text: r.mutu.target + '%', options: { align: 'center' } },
        { text: fmtPct(r.mutu.pct), options: { align: 'center', bold: true, color: scoreColor(r.mutu.pct, r.mutu.target) } }],
      ['Tiba di FAM (DOT)', { text: '20%', options: { align: 'center' } }, { text: r.fam.target + '%', options: { align: 'center' } },
        { text: fmtPct(r.fam.pct), options: { align: 'center', bold: true, color: scoreColor(r.fam.pct, r.fam.target) } }],
      ['Tiba di Distributor (DOT)', { text: '50%', options: { align: 'center' } }, { text: r.distributor.target + '%', options: { align: 'center' } },
        { text: fmtPct(r.distributor.pct), options: { align: 'center', bold: true, color: scoreColor(r.distributor.pct, r.distributor.target) } }],
      ['Reliability', { text: '20%', options: { align: 'center' } }, { text: r.reliability.target + '%', options: { align: 'center' } },
        { text: fmtPct(r.reliability.pct), options: { align: 'center', bold: true, color: scoreColor(r.reliability.pct, r.reliability.target) } }],
    ];
    s2.addTable(compRows, { x: 4.7, y: 1.6, w: 8.0, colW: [3.8, 1.3, 1.2, 1.7], fontSize: 13, fontFace: 'Calibri', color: NAVY,
      border: { pt: 0.75, color: 'E2E8F0' }, autoPage: false, rowH: 0.62, valign: 'middle' });

    // PENTING: pptxgenjs akan menghasilkan file .pptx yang KORUP kalau ada
    // nilai null/undefined di array angka utk chart. Kalau salah satu
    // komponen tidak punya data (mis. FAM kosong utk ekspedisi tertentu),
    // fallback ke 0 di sini (tabel tetap tampilkan "-" apa adanya).
    const safe = (v) => (v == null || isNaN(v) ? 0 : v);
    const compValues = [safe(r.mutu.pct), safe(r.fam.pct), safe(r.distributor.pct), safe(r.reliability.pct)];
    const compTargets = [r.mutu.target, r.fam.target, r.distributor.target, r.reliability.target];
    const compAxisMin = Math.max(0, Math.min(...compValues, ...compTargets) - 10);
    s2.addChart(pres.charts.BAR, [{ name: 'Skor (%)', labels: ['Mutu', 'FAM', 'Distributor', 'Reliability'], values: compValues }], {
      x: 4.7, y: 4.75, w: 8.0, h: 2.35, barDir: 'col',
      chartColors: compValues.map((v, i) => scoreColor(v, compTargets[i])), varyColors: true,
      chartArea: { fill: { color: LIGHT }, roundedCorners: false },
      catAxisLabelColor: GREY, valAxisLabelColor: GREY, catAxisLabelFontSize: 10, valAxisLabelFontSize: 9,
      valAxisMinVal: compAxisMin, valAxisMaxVal: 100, valGridLine: { color: 'E2E8F0', size: 0.5 }, catGridLine: { style: 'none' },
      showValue: true, dataLabelPosition: 'outEnd', dataLabelColor: NAVY, dataLabelFontSize: 10, dataLabelFormatCode: '0.00"%"',
      showLegend: false, showTitle: false
    });
    footer(s2, 2);

    // SLIDES 3-6: DETAIL PER KOMPONEN
    function detailSlide(pageNum, kicker, title, note, monthly, target) {
      let s = pres.addSlide();
      s.background = { color: WHITE };
      sectionHeader(s, kicker, title);
      s.addText(`${note}  (Target: ${target}%)`, { x: 0.6, y: 1.28, w: 11.5, h: 0.3, fontSize: 12, color: GREY, fontFace: 'Calibri', margin: 0 });

      const header = ['Bulan', 'Hit', 'Miss', 'Plan', '%'].map(t => ({ text: t, options: { bold: true, color: WHITE, fill: { color: DEEP }, align: t === 'Bulan' ? 'left' : 'center' } }));
      const tableData = [header];
      let sumHit = 0, sumMiss = 0, sumPlan = 0;
      monthly.forEach(m => { sumHit += m.hit; sumMiss += m.miss; sumPlan += m.plan; });
      const rows = monthly.concat([{ bulan: 'Jumlah', hit: sumHit, miss: sumMiss, plan: sumPlan, pct: sumPlan ? (sumHit / sumPlan) * 100 : null }]);
      rows.forEach(row => {
        const isTotal = row.bulan === 'Jumlah';
        const fill = isTotal ? LIGHT : WHITE;
        const pctColor = scoreColor(row.pct, target);
        tableData.push([
          { text: row.bulan, options: { bold: isTotal, fill: { color: fill } } },
          { text: String(row.hit), options: { align: 'center', fill: { color: fill } } },
          { text: String(row.miss), options: { align: 'center', fill: { color: fill }, color: row.miss > 0 ? RED : NAVY, bold: row.miss > 0 } },
          { text: String(row.plan), options: { align: 'center', fill: { color: fill } } },
          { text: (row.pct != null ? row.pct.toFixed(2) : '-') + '%', options: { align: 'center', fill: { color: fill }, bold: true, color: pctColor } }
        ]);
      });
      s.addTable(tableData, { x: 0.6, y: 1.75, w: 5.7, colW: [1.7, 1.0, 1.0, 1.0, 1.0], fontSize: 13, fontFace: 'Calibri', color: NAVY,
        border: { pt: 0.75, color: 'E2E8F0' }, autoPage: false, rowH: 0.55, valign: 'middle' });

      const chartLabels = rows.map(x => x.bulan);
      const chartValues = rows.map(x => (x.pct == null || isNaN(x.pct)) ? 0 : x.pct);
      const chartAxisMin = Math.max(0, Math.min(...chartValues, target) - 10);
      s.addChart([
        { type: pres.charts.BAR, data: [{ name: 'Pencapaian (%)', labels: chartLabels, values: chartValues }],
          options: { chartColors: chartValues.map(v => scoreColor(v, target)), varyColors: true } },
        { type: pres.charts.LINE, data: [{ name: `Target (${target}%)`, labels: chartLabels, values: chartLabels.map(() => target) }],
          options: { chartColors: [GREY], lineSize: 1.5, lineDataSymbol: 'none', lineDashType: 'dash' } }
      ], {
        x: 6.7, y: 1.75, w: 6.0, h: 4.3, barDir: 'col', chartArea: { fill: { color: LIGHT }, roundedCorners: false },
        catAxisLabelColor: GREY, valAxisLabelColor: GREY, catAxisLabelFontSize: 10, valAxisLabelFontSize: 9,
        valAxisMinVal: chartAxisMin, valAxisMaxVal: 100, valGridLine: { color: 'E2E8F0', size: 0.5 }, catGridLine: { style: 'none' },
        showValue: true, dataLabelPosition: 'outEnd', dataLabelColor: NAVY, dataLabelFontSize: 9, dataLabelFormatCode: '0.00"%"',
        showLegend: true, legendPos: 'b', legendFontSize: 9,
        showTitle: true, title: 'Tren Pencapaian per Bulan', titleColor: NAVY, titleFontSize: 13
      });
      footer(s, pageNum);
    }

    detailSlide(3, 'Komponen 1 — Bobot 10%', 'Mutu', 'Kesesuaian kondisi barang & dokumen pengiriman terhadap standar.', d.bulanan.mutu, r.mutu.target);
    detailSlide(4, 'Komponen 2a — Bobot 20% (DOT)', 'Delivery Time: Tiba di FAM', 'Ketepatan waktu kedatangan armada di gudang FAM sesuai jadwal.', d.bulanan.fam, r.fam.target);
    detailSlide(5, 'Komponen 2b — Bobot 50% (DOT)', 'Delivery Time: Tiba di Distributor', 'Ketepatan waktu kedatangan barang di lokasi distributor tujuan akhir.', d.bulanan.distributor, r.distributor.target);
    detailSlide(6, 'Komponen 3 — Bobot 20%', 'Reliability', 'Konsistensi pemenuhan armada terhadap rencana pengiriman (plan).', d.bulanan.reliability, r.reliability.target);

    // SLIDE 7: DETAIL MISS
    let s7 = pres.addSlide();
    s7.background = { color: WHITE };
    sectionHeader(s7, 'Root Cause', 'Detail Kejadian Miss – Delivery Time');
    const missCount = d.missDetail ? d.missDetail.length : 0;
    s7.addText(`${missCount} kejadian miss tercatat pada periode ini.`, { x: 0.6, y: 1.28, w: 11.5, h: 0.3, fontSize: 12, color: GREY, fontFace: 'Calibri', margin: 0 });

    if (missCount) {
      const missHeader = ['Bulan', 'Tujuan', 'ETA', 'ATA/No Pol', 'Keterangan'].map(t => ({ text: t, options: { bold: true, color: WHITE, fill: { color: DEEP } } }));
      const missTable = [missHeader];
      d.missDetail.slice(0, 12).forEach((m, i) => {
        const fill = i % 2 === 0 ? WHITE : LIGHT;
        missTable.push([m.bulan, m.tujuan, m.eta, m.ata, m.keterangan].map(v => ({ text: String(v || ''), options: { fill: { color: fill }, color: NAVY } })));
      });
      s7.addTable(missTable, { x: 0.6, y: 1.8, w: 12.1, colW: [1.1, 4.5, 1.5, 1.8, 3.2], fontSize: 11, fontFace: 'Calibri', color: NAVY,
        border: { pt: 0.75, color: 'E2E8F0' }, autoPage: false, rowH: 0.5, valign: 'middle' });
    } else {
      s7.addShape(pres.shapes.ROUNDED_RECTANGLE, { x: 0.6, y: 2.0, w: 12.1, h: 1.5, rectRadius: 0.06, fill: { color: LIGHT } });
      s7.addText('Tidak ada kejadian miss pada periode ini — performa Delivery Time sepenuhnya sesuai target.',
        { x: 1.0, y: 2.0, w: 11.3, h: 1.5, fontSize: 14, color: GREEN, bold: true, valign: 'middle', fontFace: 'Calibri', margin: 0 });
    }
    footer(s7, 7);

    // SLIDE 8: PENUTUP (sesuai template resmi "Terima Kasih")
    let s8 = pres.addSlide();
    s8.background = { color: WHITE };
    s8.addImage({ data: LOGO_BIG_B64, x: 2.59, y: 2.02, w: 8.16, h: 3.13, sizing: { type: 'contain', w: 8.16, h: 3.13 } });
    s8.addText('Terima Kasih', { x: 0, y: 5.35, w: W, h: 0.7, fontSize: 30, color: NAVY, bold: true, align: 'center', fontFace: 'Cambria', margin: 0 });
    s8.addText('PT. UNIFAM  —  Divisi Logistik & Transportasi', { x: 0, y: 6.05, w: W, h: 0.4, fontSize: 12, color: GREY, align: 'center', fontFace: 'Calibri', margin: 0 });

    const fileName = `Evaluasi_Kinerja_${d.ekspedisi.replace(/\s+/g, '_')}_${Date.now()}.pptx`;
    // PENTING: pres.writeFile() pakai ZIP writer bawaan pptxgenjs yang
    // menyisipkan entry folder kosong + tanpa kompresi (STORE). LibreOffice
    // & python-pptx toleran soal ini, tapi PowerPoint ASLI menolaknya dan
    // minta "Repair". Solusinya: generate ke arraybuffer dulu, lalu re-zip
    // manual pakai JSZip (proper DEFLATE, tanpa entry folder) baru didownload.
    const rawBuffer = await pres.write('arraybuffer');
    const sourceZip = await JSZip.loadAsync(rawBuffer);
    const cleanZip = new JSZip();
    const fileEntries = Object.keys(sourceZip.files).filter(name => !sourceZip.files[name].dir);
    await Promise.all(fileEntries.map(async (name) => {
      const content = await sourceZip.files[name].async('uint8array');
      cleanZip.file(name, content, { compression: 'DEFLATE', createFolders: false, dir: false });
    }));
    const cleanBlob = await cleanZip.generateAsync({ type: 'blob', compression: 'DEFLATE', mimeType: 'application/vnd.openxmlformats-officedocument.presentationml.presentation' });

    const a = document.createElement('a');
    a.href = URL.createObjectURL(cleanBlob);
    a.download = fileName;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    setTimeout(() => URL.revokeObjectURL(a.href), 5000);
  } catch (e) {
    alert('Gagal membuat PPTX: ' + e.message);
    console.error(e);
  } finally {
    btn.textContent = '⬇ Download PPTX';
    btn.disabled = false;
  }
}
